(function(){
var _FURNACE_PHOTOS = {
  "Conveyor Furnace": ["data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,"],
  "Annealing Furnace": ["data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,"]
};

function makeSlider(imgBox, photos) {
  if(imgBox.dataset.fs) return;
  imgBox.dataset.fs = '1';
  var cur = 0;

  imgBox.style.backgroundImage = 'url(' + photos[0] + ')';
  imgBox.style.backgroundSize = 'cover';
  imgBox.style.backgroundPosition = 'center';
  imgBox.style.transition = 'opacity 0.6s ease';

  var emoji = imgBox.querySelector('.text-6xl');
  if(emoji) emoji.style.display = 'none';

  var prev = document.createElement('button');
  prev.innerHTML = '&#8592;';
  prev.style.cssText = 'position:absolute;left:8px;top:50%;transform:translateY(-50%);background:rgba(0,0,0,0.5);color:#fff;border:none;width:28px;height:28px;border-radius:50%;cursor:pointer;font-size:14px;z-index:10;';

  var next = document.createElement('button');
  next.innerHTML = '&#8594;';
  next.style.cssText = 'position:absolute;right:8px;top:50%;transform:translateY(-50%);background:rgba(0,0,0,0.5);color:#fff;border:none;width:28px;height:28px;border-radius:50%;cursor:pointer;font-size:14px;z-index:10;';

  var dotBar = document.createElement('div');
  dotBar.style.cssText = 'position:absolute;bottom:8px;left:50%;transform:translateX(-50%);display:flex;gap:5px;z-index:10;';
  photos.forEach(function(_, i) {
    var d = document.createElement('div');
    d.style.cssText = 'width:' + (i===0?'16':'8') + 'px;height:8px;border-radius:4px;background:' + (i===0?'#f97316':'rgba(255,255,255,0.6)') + ';transition:all 0.3s;cursor:pointer;';
    d.onclick = function() { go(i); };
    dotBar.appendChild(d);
  });

  imgBox.style.position = 'relative';
  imgBox.appendChild(prev);
  imgBox.appendChild(next);
  imgBox.appendChild(dotBar);

  function go(n) {
    cur = n;
    imgBox.style.opacity = '0';
    setTimeout(function() {
      imgBox.style.backgroundImage = 'url(' + photos[cur] + ')';
      imgBox.style.opacity = '1';
      dotBar.querySelectorAll('div').forEach(function(d, i) {
        d.style.width = i===cur ? '16px' : '8px';
        d.style.background = i===cur ? '#f97316' : 'rgba(255,255,255,0.6)';
      });
    }, 300);
  }

  prev.onclick = function() { go((cur - 1 + photos.length) % photos.length); };
  next.onclick = function() { go((cur + 1) % photos.length); };
  setInterval(function() { go((cur + 1) % photos.length); }, 3000);
}

function initSliders() {
  var cards = document.querySelectorAll('h3');
  cards.forEach(function(h3) {
    var name = h3.textContent.trim();
    if(_FURNACE_PHOTOS[name]) {
      var card = h3.closest('.rounded-xl, .bg-white, [class*="rounded"]');
      if(card) {
        var imgBox = card.querySelector('.h-64, [class*="h-64"]');
        if(imgBox) makeSlider(imgBox, _FURNACE_PHOTOS[name]);
      }
    }
  });
}

var obs = new MutationObserver(function() {
  if(document.querySelector('h3')) { obs.disconnect(); initSliders(); }
});
obs.observe(document.documentElement, {childList:true, subtree:true});
initSliders();
})();